getDatabasesSql: SELECT name AS database_name FROM sys.databases ORDER BY name
getSchemasSql: SELECT SCHEMA_NAME AS schema_name FROM INFORMATION_SCHEMA.SCHEMATA ORDER BY SCHEMA_NAME
getTypesSql: SELECT DISTINCT DATA_TYPE AS type_name FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = 'public' ORDER BY DATA_TYPE
getTablesSql: SELECT TABLE_NAME AS table_name, TABLE_TYPE AS table_type, TABLE_SCHEMA AS table_schema FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_CATALOG = 'app' AND TABLE_SCHEMA = 'public' ORDER BY TABLE_SCHEMA, TABLE_NAME
getColumnsSql: SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = 'public' AND TABLE_NAME = 'users' ORDER BY ORDINAL_POSITION
getAllColumnsSql: SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = 'public' ORDER BY TABLE_NAME, ORDINAL_POSITION
getAllIndexesSql: SELECT i.name AS index_name, i.is_unique AS non_unique, i.type_desc AS index_type, c.name AS column_name, ic.key_ordinal AS seq_in_index, ic.is_descending_key AS descending FROM sys.indexes i JOIN sys.index_columns ic ON ic.object_id = i.object_id AND ic.index_id = i.index_id JOIN sys.columns c ON c.object_id = ic.object_id AND c.column_id = ic.column_id WHERE SCHEMA_NAME(OBJECTPROPERTY(i.object_id, 'SchemaId')) = 'public' ORDER BY i.name, ic.key_ordinal
getAllForeignKeysSql: SELECT fk.name AS constraint_name, OBJECT_SCHEMA_NAME(fkc.parent_object_id) AS table_schema, OBJECT_NAME(fkc.parent_object_id) AS table_name, COL_NAME(fkc.parent_object_id, fkc.parent_column_id) AS column_name, OBJECT_SCHEMA_NAME(fkc.referenced_object_id) AS referenced_table_schema, OBJECT_NAME(fkc.referenced_object_id) AS referenced_table_name, COL_NAME(fkc.referenced_object_id, fkc.referenced_column_id) AS referenced_column_name FROM sys.foreign_keys fk JOIN sys.foreign_key_columns fkc ON fkc.constraint_object_id = fk.object_id WHERE OBJECT_SCHEMA_NAME(fkc.parent_object_id) = 'public' ORDER BY constraint_name
getTableStatusSql: SELECT TABLE_NAME AS table_name, TABLE_TYPE AS table_type, TABLE_SCHEMA AS table_schema FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_CATALOG = 'app' AND TABLE_SCHEMA = 'public' AND TABLE_NAME = 'users'
getViewsSql: SELECT TABLE_NAME AS view_name, TABLE_SCHEMA AS table_schema, VIEW_DEFINITION AS view_definition, 0 AS materialized FROM INFORMATION_SCHEMA.VIEWS WHERE TABLE_SCHEMA = 'public' ORDER BY TABLE_SCHEMA, TABLE_NAME
getViewDefinitionSql: SELECT VIEW_DEFINITION AS definition FROM INFORMATION_SCHEMA.VIEWS WHERE TABLE_SCHEMA = 'public' AND TABLE_NAME = 'users'
getIndexesSql: SELECT * FROM sys.indexes WHERE object_id = OBJECT_ID('[app].[public].[users]') ORDER BY name
getForeignKeysSql: SELECT fk.name AS constraint_name, OBJECT_SCHEMA_NAME(fkc.parent_object_id) AS table_schema, OBJECT_NAME(fkc.parent_object_id) AS table_name, COL_NAME(fkc.parent_object_id, fkc.parent_column_id) AS column_name, OBJECT_SCHEMA_NAME(fkc.referenced_object_id) AS referenced_table_schema, OBJECT_NAME(fkc.referenced_object_id) AS referenced_table_name, COL_NAME(fkc.referenced_object_id, fkc.referenced_column_id) AS referenced_column_name FROM sys.foreign_keys fk JOIN sys.foreign_key_columns fkc ON fkc.constraint_object_id = fk.object_id WHERE OBJECT_SCHEMA_NAME(fkc.parent_object_id) = 'public' AND TABLE_NAME = 'users' AND REFERENCED_TABLE_NAME IS NOT NULL
getReferencingForeignKeysSql: SELECT * FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE WHERE REFERENCED_TABLE_SCHEMA = 'public' AND REFERENCED_TABLE_NAME = 'users' AND REFERENCED_COLUMN_NAME IS NOT NULL
getTriggersSql: SELECT * FROM INFORMATION_SCHEMA.TRIGGERS WHERE EVENT_OBJECT_SCHEMA = 'public' AND EVENT_OBJECT_TABLE = 'users'
getRoutinesSql: SELECT * FROM INFORMATION_SCHEMA.ROUTINES WHERE ROUTINE_SCHEMA = 'public'
getCheckConstraintsSql: SELECT CONSTRAINT_NAME AS constraint_name, CHECK_CLAUSE AS check_clause, 0 AS not_enforced FROM INFORMATION_SCHEMA.CHECK_CONSTRAINTS WHERE CONSTRAINT_SCHEMA = 'public' AND TABLE_NAME = 'users'
